#include <stdio.h>
#include <semaphore.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    sem_t mutex;
    sem_init(&mutex, 0, 1);     // ★ 1 = libre (binaire : 0 ou 1)
    int val;
    sem_getvalue(&mutex, &val);
    printf("Before lock: %d\n", val); // 1
    sem_wait(&mutex);           // ★ acquérir : 1→0
    printf("In critical section\n");
    sem_post(&mutex);           // ★ libérer : 0→1
    sem_getvalue(&mutex, &val);
    printf("After unlock: %d\n", val); // 1
    sem_destroy(&mutex);
    return 0;
}

